class Solution:
    def minRefuelStops(self, target, startFuel, stations):
        n = len(stations)
        dp = [startFuel] + [0] * n
        for i, (pos, fuel) in enumerate(stations):
            for t in range(i, -1, -1):
                if dp[t] >= pos:
                    dp[t + 1] = max(dp[t + 1], dp[t] + fuel)
        for t in range(n + 1):
            if dp[t] >= target:
                return t
        return -1

