var minRefuelStops = function(target, startFuel, stations) {
    const heap = [];
    const up = i => { while (i > 0) { const p = (i - 1) >> 1; if (heap[p] >= heap[i]) break; [heap[p], heap[i]] = [heap[i], heap[p]]; i = p; } };
    const down = i => { const n = heap.length; while (true) { let l = 2 * i + 1, r = l + 1, m = i; if (l < n && heap[l] > heap[m]) m = l; if (r < n && heap[r] > heap[m]) m = r; if (m === i) break; [heap[m], heap[i]] = [heap[i], heap[m]]; i = m; } };
    const push = v => { heap.push(v); up(heap.length - 1); };
    const pop = () => { const top = heap[0]; const last = heap.pop(); if (heap.length) { heap[0] = last; down(0); } return top; };
    let reach = startFuel, stops = 0, i = 0;
    const n = stations.length;
    while (reach < target) {
        while (i < n && stations[i][0] <= reach) { push(stations[i][1]); i++; }
        if (heap.length === 0) return -1;
        reach += pop();
        stops++;
    }
    return stops;
};
